import { forwardRef } from 'react';

// Base Icon component
const IconBase = forwardRef(({ size = '1em', color = 'currentColor', children, ...props }, ref) => (
  <svg ref={ref} xmlns="http://www.w3.org/2000/svg" width={size} height={size} fill={color} viewBox="0 0 256 256" {...props}>
    {children}
  </svg>
));
IconBase.displayName = 'IconBase';

// Helper to create icon component
const createIcon = (path, displayName) => {
  const Icon = forwardRef((props, ref) => (
    <IconBase ref={ref} {...props}>
      <path d={path} />
    </IconBase>
  ));
  Icon.displayName = displayName;
  return Icon;
};

